<?php
require_once __DIR__.'/../../config.php';redirect_if_not_logged_in();mb_require_any_permission($pdo,['view_plans','manage_plans']);require_once __DIR__.'/../_shared/workspace.php';ensure_maorin_workspace_tables($pdo);$can=current_user_can($pdo,'manage_plans');$projects=mb_project_options($pdo);$edit=null;if($_SERVER['REQUEST_METHOD']==='POST'&&$can){try{csrf_verify();$a=$_POST['action']??'';if($a==='save'){$id=(int)($_POST['id']??0);$filePath=trim($_POST['existing_file_path']??'');if(!empty($_FILES['file']['name'])){$dir=__DIR__.'/../../storage/uploads/business_documents';if(!is_dir($dir))mkdir($dir,0775,true);$name=preg_replace('/[^A-Za-z0-9._-]+/','_',basename($_FILES['file']['name']));$name=date('Ymd_His').'_'.bin2hex(random_bytes(3)).'_'.$name;$dest=$dir.'/'.$name;if(!move_uploaded_file($_FILES['file']['tmp_name'],$dest))throw new RuntimeException('Upload failed.');$filePath='storage/uploads/business_documents/'.$name;}$data=[$_POST['project_id']?:null,trim($_POST['related_type']??''),$_POST['related_id']?:null,trim($_POST['title']??''),trim($_POST['category']??''),trim($_POST['status']??'active'),$filePath,$_POST['expiry_date']?:null,trim($_POST['notes']??'')];if($data[3]==='')throw new RuntimeException('Title required.');if($id){$pdo->prepare("UPDATE mb_documents SET project_id=?,related_type=?,related_id=?,title=?,category=?,status=?,file_path=?,expiry_date=?,notes=? WHERE id=?")->execute([...$data,$id]);mb_set_success('Document updated.');}else{$pdo->prepare("INSERT INTO mb_documents (project_id,related_type,related_id,title,category,status,file_path,expiry_date,notes,created_by) VALUES (?,?,?,?,?,?,?,?,?,?)")->execute([...$data,(int)$_SESSION['user_id']]);mb_set_success('Document created.');}}elseif($a==='delete'){$pdo->prepare("DELETE FROM mb_documents WHERE id=?")->execute([(int)$_POST['id']]);mb_set_success('Document deleted.');}}catch(Throwable $e){mb_set_error($e->getMessage());}mb_redirect('index.php');}if(isset($_GET['edit'])){$st=$pdo->prepare("SELECT * FROM mb_documents WHERE id=?");$st->execute([(int)$_GET['edit']]);$edit=$st->fetch(PDO::FETCH_ASSOC);} $rows=$pdo->query("SELECT d.*,p.name project_name FROM mb_documents d LEFT JOIN mb_projects p ON p.id=d.project_id ORDER BY d.updated_at DESC,d.id DESC")->fetchAll(PDO::FETCH_ASSOC);[$ok,$err]=mb_flash();mb_workspace_header($pdo,'Plans and Revisions','Plans');?><?php if($ok):?><div class="alert alert-success"><?=htmlspecialchars($ok)?></div><?php endif;?><?php if($err):?><div class="alert alert-danger"><?=htmlspecialchars($err)?></div><?php endif;?><div class="mb-card"><div class="mb-card-header"><div><strong>Plan and revision center</strong><div class="text-muted small">Floor plans, architectural plans, revisions, and approval records.</div></div><?php if($can):?><button class="btn btn-primary" data-mb-open-modal="docModal">New Plan File</button><?php endif;?></div><div class="table-responsive"><table class="table mb-table"><thead><tr><th>Title</th><th>Project</th><th>Category</th><th>Status</th><th>Expiry</th><th>File</th><th></th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><strong><?=htmlspecialchars($r['title'])?></strong><div class="small text-muted"><?=htmlspecialchars($r['notes'])?></div></td><td><?=htmlspecialchars($r['project_name']?:'-')?></td><td><?=htmlspecialchars($r['category'])?></td><td><span class="mb-badge"><?=htmlspecialchars($r['status'])?></span></td><td><?=htmlspecialchars($r['expiry_date']?:'-')?></td><td><?php if($r['file_path']):?><a href="<?=htmlspecialchars(mb_base_url($r['file_path']))?>" target="_blank">Open</a><?php else:?>-<?php endif;?></td><td class="mb-actions"><?php if($can):?><a class="btn btn-sm btn-outline-primary" href="?edit=<?=(int)$r['id']?>">Edit</a><form method="post"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?=(int)$r['id']?>"><button class="btn btn-sm btn-outline-danger" data-confirm="Delete document?">Delete</button></form><?php endif;?></td></tr><?php endforeach;if(!$rows):?><tr><td colspan="7" class="text-center text-muted py-4">No plan files yet.</td></tr><?php endif;?></tbody></table></div></div><div class="modal fade" id="docModal"><div class="modal-dialog modal-lg"><form method="post" enctype="multipart/form-data" class="modal-content mb-modal-panel"><input type="hidden" name="csrf_token" value="<?=htmlspecialchars(csrf_token())?>"><input type="hidden" name="action" value="save"><input type="hidden" name="id" value="<?=(int)($edit['id']??0)?>"><input type="hidden" name="existing_file_path" value="<?=htmlspecialchars($edit['file_path']??'')?>"><div class="modal-header"><h5 class="modal-title"><?=$edit?'Edit':'New'?> Plan File</h5><button class="btn-close" type="button" data-bs-dismiss="modal"></button></div><div class="modal-body"><div class="mb-form-grid"><label>Project<select class="form-select" name="project_id"><option value="">No project</option><?php foreach($projects as $p):?><option value="<?=(int)$p['id']?>" <?=((int)($edit['project_id']??0)===(int)$p['id']?'selected':'')?>><?=htmlspecialchars($p['name'])?></option><?php endforeach;?></select></label><label>Title<input required class="form-control" name="title" value="<?=htmlspecialchars($edit['title']??'')?>"></label><label>Category<input class="form-control" name="category" value="<?=htmlspecialchars($edit['category']??'')?>"></label><label>Status<input class="form-control" name="status" value="<?=htmlspecialchars($edit['status']??'active')?>"></label><label>Related Type<input class="form-control" name="related_type" value="<?=htmlspecialchars($edit['related_type']??'')?>"></label><label>Related ID<input class="form-control" type="number" name="related_id" value="<?=htmlspecialchars($edit['related_id']??'')?>"></label><label>Expiry Date<input class="form-control" type="date" name="expiry_date" value="<?=htmlspecialchars($edit['expiry_date']??'')?>"></label><label>File<input class="form-control" type="file" name="file"></label><label class="full">Notes<textarea class="form-control" name="notes"><?=htmlspecialchars($edit['notes']??'')?></textarea></label></div></div><div class="modal-footer"><button class="btn btn-primary">Save Document</button></div></form></div></div><script><?php if($edit):?>new bootstrap.Modal(document.getElementById('docModal')).show();<?php endif;?></script><?php mb_workspace_footer();?>